command:
// ======================================
// Roguelike 连续抽取宏管理器
// ======================================
// 打开连续抽取宏管理器，GM可以创建连续抽取宏。
// 连续抽取宏会按顺序串行执行多个配置的抽取宏。
// ======================================

if (!game.user.isGM) {
  ui.notifications.error('只有 GM 可以使用连续抽取宏管理器');
} else {
  const mod = game.modules.get('ai-pf2e-assistant');
  if (!mod?.api?.roguelike?.openSequentialManager) {
    ui.notifications.warn('Roguelike 连续抽取宏管理器不可用，请确认模块已启用');
  } else {
    mod.api.roguelike.openSequentialManager();
  }
}
